import React, {useEffect, useState} from "react";
import "./BuscarCitas.css";
// import userImg from '../images/user.png'; // Descomenta si tienes imágenes

// Datos de ejemplo por defecto
const defaultMedicos = [
    {
        id: 1,
        nombre: "Dra. Ana Pérez",
        especialidad: "Cardiología",
        localidad: "San José",
        costoConsulta: "₡35,000"
    },
    {
        id: 2,
        nombre: "Dr. Luis Gómez",
        especialidad: "Dermatología",
        localidad: "Heredia",
        costoConsulta: "₡30,000"
    }
];

const defaultCitasPorMedico = {
    "1H": [
        { key: "20/05/2025", value: ["08:00", "09:00", "10:00"] },
        { key: "21/05/2025", value: ["11:00", "12:00"] }
    ],
    "1O": {
        "20/05/2025": ["09:00"], // 09:00 está ocupada
        "21/05/2025": []
    },
    "2H": [
        { key: "20/05/2025", value: ["13:00", "14:00"] }
    ],
    "2O": {
        "20/05/2025": []
    }
};

const defaultFechaAct = "20-05-2025";

// Modifica la función para usar los datos por defecto si no recibe props
function BuscarCitas({
                         fechaAct = defaultFechaAct
                     }) {
    const [medicos, setMedicos] = useState([]);
    const backend="http://localhost:8080";
    const [especialidad, setEspecialidad] = useState("");
    const [localidad, setLocalidad] = useState("");


    useEffect(()=>{
        if(medicos.length === 0)
            handleList();
    }, [])

    const handleSubmit = (e) => {
        e.preventDefault();
        // Aquí deberías llamar a tu API o función de búsqueda
        // Ejemplo: buscarMedicos(especialidad, localidad)
    };

    function adaptHorarios(medico) {
        // Agrupa los horarios por fecha ficticia (puedes cambiar esto si tienes la fecha real)
        // Aquí, como ejemplo, agrupamos por día de la semana como "fecha"
        const horariosPorFecha = {};
        (medico.horarios || []).forEach(horario => {
            // Puedes cambiar esta lógica si tienes la fecha real
            const fecha = `Día ${horario.diaSemana}`;
            if (!horariosPorFecha[fecha]) {
                horariosPorFecha[fecha] = [];
            }
            horariosPorFecha[fecha].push(`${horario.horaInicio} - ${horario.horaFin}`);
        });
        // Convierte a la estructura esperada
        const horariosAdaptados = Object.entries(horariosPorFecha).map(([fecha, horas]) => ({
            fecha,
            horas
        }));
        return {
            ...medico,
            horarios: horariosAdaptados
        };
    }

    function handleList(){
        const request = new Request(backend+"/", {method: "GET",
            headers:{"Accept":"application/json","Content-Type":"application/json"}});
        (async ()=>{
            const response = await fetch(request);
            if(!response.ok){
                alert("Error: "+ response.statusText);
                return;
            }
            let medicos = await response.json();
            // Adaptar los horarios de cada médico
            medicos = medicos.map(adaptHorarios);
            setMedicos(medicos);
        })();
    }

    return (
        <div className="search-container">
            <div className="search-form">
                <form onSubmit={handleSubmit}>
                    <input
                        type="text"
                        name="especialidad"
                        placeholder="Especialidad"
                        value={especialidad}
                        onChange={e => setEspecialidad(e.target.value)}
                    />
                    <input
                        type="text"
                        name="localidad"
                        placeholder="Ciudad o Provincia"
                        value={localidad}
                        onChange={e => setLocalidad(e.target.value)}
                    />
                    <button type="submit">Buscar</button>
                </form>
            </div>

            <div className="doctor-list">
                {medicos.length > 0 ? (
                    <ul>
                        {medicos.map(medico => (
                            <li key={medico.id}>
                                <div className="doctor-card">
                                    <div>
                                        <div className="doctor-info">
                                            <img src="#" alt="Doctor" className="doctor-photo" />
                                            <div className="doctor-details">
                                                <h3>
                                                    <span>{medico.nombre}</span>
                                                    <span className="doctor-code">{medico.costoConsulta}</span>
                                                </h3>
                                                <p>{medico.especialidad}</p>
                                            </div>
                                        </div>
                                        <div className="doctor-location">
                                            <span>Donde consulta</span>
                                            <span className="location-pin">@</span>
                                            <span>{medico.localidad}</span>
                                        </div>
                                    </div>

                                    {/* Horarios disponibles */}
                                    {(medico.horarios || []).length > 0 ? (
                                        medico.horarios.map(listaH => (
                                            <div className="citas" key={listaH.fecha}>
                                                <div className="cita-day">
                                                    <div className="cita-date">{listaH.fecha}</div>
                                                    <div className="cita-times">
                                                        <ul className="lista-horas">
                                                            {(listaH.horas || []).map(hora => (
                                                                <li key={hora}>
                                                                    {hora}
                                                                </li>
                                                            ))}
                                                        </ul>
                                                    </div>
                                                </div>
                                            </div>
                                        ))
                                    ) : (
                                        <div className="citas">
                                            <div className="cita-day">
                                                <div className="cita-date">No hay horarios disponibles</div>
                                            </div>
                                        </div>
                                    )}

                                    <button className="schedule-btn">
                                        <a href={`/presentation/horarios/show/${medico.id}/${fechaAct}`}>Schedule →</a>
                                    </button>
                                </div>
                            </li>
                        ))}
                    </ul>
                ) : (
                    <p>No hay médicos para mostrar.</p>
                )}
            </div>
        </div>
    );
}

export default BuscarCitas;
